import torch
import torch.nn as nn

class LinearMLP(nn.Module):
    def __init__(self, in_channels=61, hidden_dim=64, num_tasks=128, dropout=0.2):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(in_channels, hidden_dim),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, hidden_dim),
            nn.ReLU(),
            nn.Dropout(dropout),
            nn.Linear(hidden_dim, num_tasks)
        )
    def forward(self, x):
        return self.net(x)
